const renumberQueueItems = `-- name: RenumberQueueItems :exec
UPDATE play_queue_items p
SET ord = sub.new_ord
FROM (
    SELECT it.id,
           (SELECT COALESCE(MAX(mx.ord), 0) FROM play_queue_items mx WHERE mx.queue_id = $1)
           + 1024 * row_number() OVER (ORDER BY it.ord, it.id) AS new_ord
    FROM play_queue_items it
    WHERE it.queue_id = $1
) sub
WHERE p.id = sub.id
`

// Full renumber preserving current order — run when a move/insert finds
// no usable gap.
func (q *Queries) RenumberQueueItems(ctx context.Context, queueID int64) error {
	_, err := q.db.Exec(ctx, renumberQueueItems, queueID)
	return err
}

const reorderUpcoming = `-- name: ReorderUpcoming :exec
UPDATE play_queue_items p
SET ord = sub.new_ord
FROM (
    SELECT it.id,
           (SELECT COALESCE(MAX(mx.ord), 0) FROM play_queue_items mx WHERE mx.queue_id = $1)
           + 1024 * row_number() OVER (
               ORDER BY CASE WHEN $2::boolean THEN random() END NULLS LAST, it.src_ord, it.id
             ) AS new_ord
    FROM play_queue_items it
    WHERE it.queue_id = $1 AND it.ord > $3
) sub
WHERE p.id = sub.id
`

type ReorderUpcomingParams struct {
	QueueID  int64 `json:"queue_id"`
	Shuffle  bool  `json:"shuffle"`
	AfterOrd int64 `json:"after_ord"`
}

// Rewrite the tail after after_ord into a fresh range above max(ord):
// shuffle=true orders randomly, shuffle=false restores the source's
// natural order (src_ord). Both are the same one-statement rewrite.
func (q *Queries) ReorderUpcoming(ctx context.Context, arg ReorderUpcomingParams) error {
	_, err := q.db.Exec(ctx, reorderUpcoming, arg.QueueID, arg.Shuffle, arg.AfterOrd)
	return err
}

